public final class LedgerManager: LedgerManaging {
    private let storage: LedgerStorage
    private let queue = DispatchQueue(label: "com.example.bankapp.ledger.queue", qos: .userInitiated)
    private var _snapshot: LedgerSnapshot

    public var snapshot: LedgerSnapshot {
        queue.sync { _snapshot }
    }

    public init(storage: LedgerStorage = EncryptedFileLedgerStorage()) {
        self.storage = storage
        self._snapshot = (try? storage.load()) ?? LedgerSnapshot()
    }

    public func refresh() throws {
        try queue.sync {
            _snapshot = try storage.load()
        }
    }

    public func createAccount(id: String, name: String, currency: String, initialBalanceCents: Int64) throws {
        try queue.sync {
            guard initialBalanceCents >= 0 else { throw BankingError.invalidAmount }
            var snap = _snapshot
            if let existing = snap.accounts[id] {
                var updated = existing
                updated.name = name
                updated.currency = currency
                updated.updatedAt = Date()
                snap.accounts[id] = updated
            } else {
                snap.accounts[id] = Account(id: id, name: name, currency: currency, balanceCents: initialBalanceCents, updatedAt: Date())
            }
            snap.revision &+= 1
            snap.updatedAt = Date()
            try storage.save(snap)
            _snapshot = snap
        }
    }

    public func deposit(to accountId: String, amountCents: Int64, currency: String, memo: String? = nil) throws -> Transaction {
        try queue.sync {
            guard amountCents > 0 else { throw BankingError.invalidAmount }
            var snap = _snapshot
            guard var acct = snap.accounts[accountId] else { throw BankingError.accountNotFound(accountId) }
            guard acct.currency == currency else { throw BankingError.currencyMismatch }

            acct.balanceCents = safeAdd(acct.balanceCents, amountCents)
            acct.updatedAt = Date()
            snap.accounts[accountId] = acct

            let tx = Transaction(
                type: .deposit,
                amountCents: amountCents,
                currency: currency,
                sourceAccountId: nil,
                destinationAccountId: accountId,
                memo: memo,
                createdAt: Date()
            )
            snap.transactions.append(tx)
            snap.revision &+= 1
            snap.updatedAt = Date()
            try storage.save(snap)
            _snapshot = snap
            return tx
        }
    }

    public func withdraw(from accountId: String, amountCents: Int64, currency: String, memo: String? = nil) throws -> Transaction {
        try queue.sync {
            guard amountCents > 0 else { throw BankingError.invalidAmount }
            var snap = _snapshot
            guard var acct = snap.accounts[accountId] else { throw BankingError.accountNotFound(accountId) }
            guard acct.currency == currency else { throw BankingError.currencyMismatch }
            guard acct.balanceCents >= amountCents else { throw BankingError.insufficientFunds }

            acct.balanceCents = safeSub(acct.balanceCents, amountCents)
            acct.updatedAt = Date()
            snap.accounts[accountId] = acct

            let tx = Transaction(
                type: .withdrawal,
                amountCents: amountCents,
                currency: currency,
                sourceAccountId: accountId,
                destinationAccountId: nil,
                memo: memo,
                createdAt: Date()
            )
            snap.transactions.append(tx)
            snap.revision &+= 1
            snap.updatedAt = Date()
            try storage.save(snap)
            _snapshot = snap
            return tx
        }
    }

    public func transfer(from sourceAccountId: String, to destinationAccountId: String, amountCents: Int64, currency: String, memo: String? = nil) throws -> Transaction {
        try queue.sync {
            guard amountCents > 0 else { throw BankingError.invalidAmount }
            guard sourceAccountId != destinationAccountId else { throw BankingError.invalidTransferAccounts }
            var snap = _snapshot
            guard var src = snap.accounts[sourceAccountId] else { throw BankingError.accountNotFound(sourceAccountId) }
            guard var dst = snap.accounts[destinationAccountId] else { throw BankingError.accountNotFound(destinationAccountId) }
            guard src.currency == currency, dst.currency == currency else { throw BankingError.currencyMismatch }
            guard src.balanceCents >= amountCents else { throw BankingError.insufficientFunds }

            src.balanceCents = safeSub(src.balanceCents, amountCents)
            src.updatedAt = Date()
            dst.balanceCents = safeAdd(dst.balanceCents, amountCents)
            dst.updatedAt = Date()

            snap.accounts[sourceAccountId] = src
            snap.accounts[destinationAccountId] = dst

            let tx = Transaction(
                type: .transfer,
                amountCents: amountCents,
                currency: currency,
                sourceAccountId: sourceAccountId,
                destinationAccountId: destinationAccountId,
                memo: memo,
                createdAt: Date()
            )
            snap.transactions.append(tx)
            snap.revision &+= 1
            snap.updatedAt = Date()
            try storage.save(snap)
            _snapshot = snap
            return tx
        }
    }

    private func safeAdd(_ a: Int64, _ b: Int64) -> Int64 {
        let (res, overflow) = a.addingReportingOverflow(b)
        return overflow ? Int64.max : res
    }

    private func safeSub(_ a: Int64, _ b: Int64) -> Int64 {
        let (res, overflow) = a.subtractingReportingOverflow(b)
        return overflow ? Int64.min : res
    }
}

// MARK: - Formatting

public struct MoneyFormatter {
    public static func string(amountCents: Int64, currencyCode: String, locale: Locale = .current) -> String {
        let nf = NumberFormatter()
        nf.numberStyle = .currency
        nf.currencyCode = currencyCode
        nf.locale = locale
        nf.maximumFractionDigits = 2
        nf.minimumFractionDigits = 2
        let amount = NSDecimalNumber(value: amountCents).dividing(by: NSDecimalNumber(value: 100))
        return nf.string(from: amount) ?? "\(amount)"
    }
}

