public final class AccountsViewModel {
    public struct AccountRow: Equatable {
        public let id: String
        public let name: String
        public let balanceText: String
        public let currency: String
        public let updatedAt: Date
    }

    public private(set) var accountRows: [AccountRow] = []
    public private(set) var transactions: [Transaction] = []
    public var onUpdate: (() -> Void)?
    public var onError: ((Error) -> Void)?

    private let ledger: LedgerManaging
    private let locale: Locale

    public init(ledger: LedgerManaging = LedgerManager(), locale: Locale = .current) {
        self.ledger = ledger
        self.locale = locale
        reloadFromLedger()
    }

    public func reload() {
        do {
            try ledger.refresh()
            reloadFromLedger()
        } catch {
            onError?(error)
        }
    }

    public func seedIfNeeded() {
        let snap = ledger.snapshot
        guard snap.accounts.isEmpty else { return }
        do {
            try ledger.createAccount(id: "checking", name: "Checking", currency: "USD", initialBalanceCents: 250_000)
            try ledger.createAccount(id: "savings", name: "Savings", currency: "USD", initialBalanceCents: 1_500_000)
            _ = try ledger.deposit(to: "checking", amountCents: 20_000, currency: "USD", memo: "Paycheck")
            _ = try ledger.transfer(from: "checking", to: "savings", amountCents: 50_000, currency: "USD", memo: "Auto-save")
            reloadFromLedger()
        } catch {
            onError?(error)
        }
    }

    public func deposit(accountId: String, amountCents: Int64, currency: String, memo: String? = nil) {
        do {
            _ = try ledger.deposit(to: accountId, amountCents: amountCents, currency: currency, memo: memo)
            reloadFromLedger()
        } catch {
            onError?(error)
        }
    }

    public func withdraw(accountId: String, amountCents: Int64, currency: String, memo: String? = nil) {
        do {
            _ = try ledger.withdraw(from: accountId, amountCents: amountCents, currency: currency, memo: memo)
            reloadFromLedger()
        } catch {
            onError?(error)
        }
    }

    public func transfer(sourceAccountId: String, destinationAccountId: String, amountCents: Int64, currency: String, memo: String? = nil) {
        do {
            _ = try ledger.transfer(from: sourceAccountId, to: destinationAccountId, amountCents: amountCents, currency: currency, memo: memo)
            reloadFromLedger()
        } catch {
            onError?(error)
        }
    }

    private func reloadFromLedger() {
        let snap = ledger.snapshot
        let accounts = snap.accounts.values.sorted { $0.name.localizedCaseInsensitiveCompare($1.name) == .orderedAscending }
        accountRows = accounts.map { acct in
            AccountRow(
                id: acct.id,
                name: acct.name,
                balanceText: MoneyFormatter.string(amountCents: acct.balanceCents, currencyCode: acct.currency, locale: locale),
                currency: acct.currency,
                updatedAt: acct.updatedAt
            )
        }
        transactions = snap.transactions.sorted { $0.createdAt > $1.createdAt }
        onUpdate?()
    }
}

// MARK: - UI

public final class AccountsViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    private let viewModel: AccountsViewModel
    private let tableView = UITableView(frame: .zero, style: .insetGrouped)

    private enum Section: Int, CaseIterable {
        case accounts
        case transactions

        var title: String {
            switch self {
            case .accounts: return "Accounts"
            case .transactions: return "Recent Transactions"
            }
        }
    }

    public init(viewModel: AccountsViewModel = AccountsViewModel()) {
        self.viewModel = viewModel
        super.init(nibName: nil, bundle: nil)
        self.title = "Banking"
        self.tabBarItem = UITabBarItem(title: "Banking", image: UIImage(systemName: "creditcard"), tag: 0)
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    public override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        navigationItem.rightBarButtonItems = [
            UIBarButtonItem(title: "Seed", style: .plain, target: self, action: #selector(seedTapped)),
            UIBarButtonItem(title: "New Tx", style: .plain, target: self, action: #selector(newTxTapped))
        ]

        tableView.dataSource = self
        tableView.delegate = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "cell")
        tableView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(tableView)

        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])

        viewModel.onUpdate = { [weak self] in self?.tableView.reloadData() }
        viewModel.onError = { [weak self] error in
            self?.presentAlert(title: "Error", message: (error as NSError).localizedDescription)
        }

        viewModel.reload()
    }

    @objc private func seedTapped() {
        viewModel.seedIfNeeded()
    }

    @objc private func newTxTapped() {
        let vc = TransactionComposerViewController(viewModel: viewModel)
        let nav = UINavigationController(rootViewController: vc)
        nav.modalPresentationStyle = .formSheet
        present(nav, animated: true)
    }

    public func numberOfSections(in tableView: UITableView) -> Int { Section.allCases.count }

    public func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        Section(rawValue: section)?.title
    }

    public func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        guard let s = Section(rawValue: section) else { return 0 }
        switch s {
        case .accounts: return viewModel.accountRows.count
        case .transactions: return min(viewModel.transactions.count, 25)
        }
    }

    public func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
        cell.selectionStyle = .none
        guard let s = Section(rawValue: indexPath.section) else { return cell }

        switch s {
        case .accounts:
            let row = viewModel.accountRows[indexPath.row]
            var content = cell.defaultContentConfiguration()
            content.text = row.name
            content.secondaryText = row.balanceText
            content.secondaryTextProperties.color = .secondaryLabel
            cell.contentConfiguration = content
            cell.accessoryType = .disclosureIndicator
        case .transactions:
            let tx = viewModel.transactions[indexPath.row]
            var content = cell.defaultContentConfiguration()
            content.text = txSummary(tx)
            content.secondaryText = DateFormatter.localizedString(from: tx.createdAt, dateStyle: .medium, timeStyle: .short)
            content.secondaryTextProperties.color = .secondaryLabel
            cell.contentConfiguration = content
        }
        return cell
    }

    public func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        guard let s = Section(rawValue: indexPath.section) else { return }
        if s == .accounts {
            let row = viewModel.accountRows[indexPath.row]
            let vc = AccountDetailViewController(accountId: row.id, viewModel: viewModel)
            navigationController?.pushViewController(vc, animated: true)
        }
    }

    private func txSummary(_ tx: Transaction) -> String {
        let amt = MoneyFormatter.string(amountCents: tx.amountCents, currencyCode: tx.currency)
        switch tx.type {
        case .deposit:
            return "Deposit \(amt) → \(tx.destinationAccountId ?? "")"
        case .withdrawal:
            return "Withdrawal \(amt) ← \(tx.sourceAccountId ?? "")"
        case .transfer:
            return "Transfer \(amt): \(tx.sourceAccountId ?? "") → \(tx.destinationAccountId ?? "")"
        }
    }

    private func presentAlert(title: String, message: String) {
        let a = UIAlertController(title: title, message: message, preferredStyle: .alert)
        a.addAction(UIAlertAction(title: "OK", style: .default))
        present(a, animated: true)
    }
}

