        if indexPath.section == 0 {
            let row = accountRow
            if indexPath.row == 0 {
                content.text = row?.name ?? accountId
                content.secondaryText = "Account ID: \(accountId)"
            } else {
                content.text = "Available Balance"
                content.secondaryText = row?.balanceText ?? "-"
                content.secondaryTextProperties.color = .secondaryLabel
            }
        } else {
            let filtered = Array(viewModel.transactions.filter { $0.sourceAccountId == accountId || $0.destinationAccountId == accountId }.prefix(50))
            let tx = filtered[indexPath.row]
            content.text = txLine(tx)
            content.secondaryText = DateFormatter.localizedString(from: tx.createdAt, dateStyle: .medium, timeStyle: .short)
            content.secondaryTextProperties.color = .secondaryLabel
        }

        cell.contentConfiguration = content
        return cell
    }

    private func txLine(_ tx: Transaction) -> String {
        let amt = MoneyFormatter.string(amountCents: tx.amountCents, currencyCode: tx.currency)
        switch tx.type {
        case .deposit:
            return "Deposit \(amt)"
        case .withdrawal:
            return "Withdrawal \(amt)"
        case .transfer:
            let other = (tx.sourceAccountId == accountId) ? (tx.destinationAccountId ?? "") : (tx.sourceAccountId ?? "")
            let dir = (tx.sourceAccountId == accountId) ? "→" : "←"
            return "Transfer \(amt) \(dir) \(other)"
        }
    }

    private func presentAlert(title: String, message: String) {
        let a = UIAlertController(title: title, message: message, preferredStyle: .alert)
        a.addAction(UIAlertAction(title: "OK", style: .default))
        present(a, animated: true)
    }
}

public final class TransactionComposerViewController: UIViewController {
    private let viewModel: AccountsViewModel

    private let typeControl = UISegmentedControl(items: ["Deposit", "Withdraw", "Transfer"])
    private let fromField = UITextField()
    private let toField = UITextField()
    private let amountField = UITextField()
    private let memoField = UITextField()
    private let currencyField = UITextField()

    public init(viewModel: AccountsViewModel) {
        self.viewModel = viewModel
        super.init(nibName: nil, bundle: nil)
        self.title = "New Transaction"
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    public override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        navigationItem.leftBarButtonItem = UIBarButtonItem(barButtonSystemItem: .cancel, target: self, action: #selector(cancelTapped))
        navigationItem.rightBarButtonItem = UIBarButtonItem(title: "Post", style: .done, target: self, action: #selector(postTapped))

        typeControl.selectedSegmentIndex = 0
        typeControl.addTarget(self, action: #selector(typeChanged), for: .valueChanged)

        configureField(fromField, placeholder: "From Account ID (for withdraw/transfer)")
        configureField(toField, placeholder: "To Account ID (for deposit/transfer)")
        configureField(amountField, placeholder: "Amount (e.g. 12.34)")
        amountField.keyboardType = .decimalPad
        configureField(currencyField, placeholder: "Currency (e.g. USD)")
        currencyField.autocapitalizationType = .allCharacters
        currencyField.text = viewModel.accountRows.first?.currency ?? "USD"
        configureField(memoField, placeholder: "Memo (optional)")

        let stack = UIStackView(arrangedSubviews: [typeControl, fromField, toField, amountField, currencyField, memoField])
        stack.axis = .vertical
        stack.spacing = 12
        stack.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(stack)

        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            stack.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor, constant: -16)
        ])

        applyTypeVisibility()
        prefillSuggestedAccounts()
    }

    private func configureField(_ field: UITextField, placeholder: String) {
        field.placeholder = placeholder
        field.borderStyle = .roundedRect
        field.autocorrectionType = .no
        field.autocapitalizationType = .none
        field.clearButtonMode = .whileEditing
    }

    @objc private func typeChanged() {
        applyTypeVisibility()
        prefillSuggestedAccounts()
    }

    private func applyTypeVisibility() {
        let idx = typeControl.selectedSegmentIndex
        switch idx {
        case 0: // deposit
            fromField.isHidden = true
            toField.isHidden = false
        case 1: // withdraw
            fromField.isHidden = false
            toField.isHidden = true
        default: // transfer
            fromField.isHidden = false
            toField.isHidden = false
        }
    }

    private func prefillSuggestedAccounts() {
        let ids = viewModel.accountRows.map { $0.id }
        if typeControl.selectedSegmentIndex == 0 {
            toField.text = toField.text?.isEmpty == false ? toField.text : ids.first
        } else if typeControl.selectedSegmentIndex == 1 {
            fromField.text = fromField.text?.isEmpty == false ? fromField.text : ids.first
        } else {
            fromField.text = fromField.text?.isEmpty == false ? fromField.text : ids.first
            toField.text = toField.text?.isEmpty == false ? toField.text : (ids.dropFirst().first ?? ids.first)
        }
    }

    @objc private func cancelTapped() {
        dismiss(animated: true)
    }

    @objc private func postTapped() {
        let currency = (currencyField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let memo = memoField.text?.trimmingCharacters(in: .whitespacesAndNewlines)
        let amountCents = parseAmountToCents(amountField.text ?? "")

        guard !currency.isEmpty else {
            presentAlert(title: "Invalid", message: "Currency is required.")
            return
        }
        guard amountCents > 0 else {
            presentAlert(title: "Invalid", message: "Enter a valid amount.")
            return
        }

        switch typeControl.selectedSegmentIndex {
        case 0:
            let to = (toField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !to.isEmpty else { presentAlert(title: "Invalid", message: "To Account ID required."); return }
            viewModel.deposit(accountId: to, amountCents: amountCents, currency: currency, memo: memo)
            dismiss(animated: true)
        case 1:
            let from = (fromField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !from.isEmpty else { presentAlert(title: "Invalid", message: "From Account ID required."); return }
            viewModel.withdraw(accountId: from, amountCents: amountCents, currency: currency, memo: memo)
            dismiss(animated: true)
        default:
            let from = (fromField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let to = (toField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            guard !from.isEmpty, !to.isEmpty else { presentAlert(title: "Invalid", message: "Both Account IDs required."); return }
            viewModel.transfer(sourceAccountId: from, destinationAccountId: to, amountCents: amountCents, currency: currency, memo: memo)
            dismiss(animated: true)
        }
    }

    private func parseAmountToCents(_ text: String) -> Int64 {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return 0 }
        let normalized = trimmed.replacingOccurrences(of: ",", with: ".")
        let dec = Decimal(string: normalized) ?? 0
        let cents = (dec * 100 as NSDecimalNumber).rounding(accordingToBehavior: nil)
        return (cents as NSDecimalNumber).int64Value
    }

    private func presentAlert(title: String, message: String) {
        let a = UIAlertController(title: title, message: message, preferredStyle: .alert)
        a.addAction(UIAlertAction(title: "OK", style: .default))
        present(a, animated: true)
    }
}

